import { Type } from "typebox";
import { shortenLabel } from "../token-saver.ts";
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import type { Specialist } from "./types.ts";
import { SPECIALISTS } from "./specialists.ts";
